import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Email validation function
  const validateEmail = (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  // Validation handlers
  const validateStep1 = (): boolean => {
    let isValid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email');
      isValid = false;
    } else {
      setEmailError('');
    }
    return isValid;
  };

  // Handle name change with validation
  const handleNameChange = (value: string) => {
    setName(value);
    if (value.trim()) {
      setNameError('');
    }
  };

  // Handle email change with validation
  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (value.trim() && validateEmail(value)) {
      setEmailError('');
    }
  };

  // Handle feature toggle
  const handleFeatureToggle = (feature: string) => {
    setFeatures(prev =>
      prev.includes(feature)
        ? prev.filter(f => f !== feature)
        : [...prev, feature]
    );
  };

  // Navigate to next step
  const handleNext = () => {
    if (currentStep === 1 && !validateStep1()) {
      return;
    }
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  };

  // Navigate to previous step
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  // Handle final submission
  const handleSubmit = () => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments
    });
  };

  // Check if Step 1 is valid for enabling Next button
  // Memoized Step 1 validation — checks name, email presence, and email format
  // Memoized Step 1 validation — checks name, email presence, and email format
  const isStep1Valid = useMemo(() => {
    return name.trim() && email.trim() && validateEmail(email);
  }, [name, email]);

  // Memoized Step 2 validation — satisfaction rating selected
  const isStep2Valid = useMemo(() => {
    return satisfaction !== '';
  }, [satisfaction]);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-4)" align="center">
          <Heading level={1}>Customer Feedback Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 4
          </Text>
        </Stack>

        {/* Progress Bar */}
        <Progress
          value={currentStep}
          max={4}
          variant="default"
          size="md"
          showLabel={false}
        />

        {/* Content Area */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Personal Information</Heading>
              <Input
                label="Name"
                required
                value={name}
                onChange={handleNameChange}
                placeholder="Enter your name"
                error={nameError}
              />
              <Input
                label="Email"
                required
                type="email"
                value={email}
                onChange={handleEmailChange}
                placeholder="Enter your email"
                error={emailError}
              />
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you with our service?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label: `${index + 1} - ${label}`
                }))}
                direction="vertical"
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Which features are you interested in?
              </Text>
              <Stack gap="var(--ggui-spacing-3)" align="start">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

          {currentStep === 4 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Comments</Heading>
              <TextArea
                label="Additional Comments"
                value={comments}
                onChange={setComments}
                placeholder="Share any additional feedback (optional)"
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          )}

          {currentStep === 5 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Review Your Answers</Heading>
              <Divider />
              <Stack gap="var(--ggui-spacing-4)">
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Name
                  </Text>
                  <Text>{name}</Text>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Email
                  </Text>
                  <Text>{email}</Text>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Satisfaction Rating
                  </Text>
                  <Text>
                    {satisfaction ? `${satisfaction} - ${props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}` : 'Not provided'}
                  </Text>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Feature Interests
                  </Text>
                  <Stack gap="var(--ggui-spacing-2)" align="start" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                    {features.length > 0 ? (
                      features.map(f => <Badge key={f} variant="primary">{f}</Badge>)
                    ) : (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        None selected
                      </Text>
                    )}
                  </Stack>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Comments
                  </Text>
                  <Text>
                    {comments || '(No comments provided)'}
                  </Text>
                </div>
              </Stack>
            </Stack>
          )}
        </Card>

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {currentStep < 4 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={
                  (currentStep === 1 && !isStep1Valid) ||
                  (currentStep === 2 && !isStep2Valid)
                }
              >
                Next
              </Button>
            )}
            {currentStep === 4 && (
              <Button
                variant="primary"
                onClick={() => setCurrentStep(5)}
              >
                Review
              </Button>
            )}
            {currentStep === 5 && (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit
              </Button>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>
  );
}

