                            )}

                            {/* Edit/Save buttons for title */}
                            {editingTaskId === task.id && (
                              <Row gap={8} justify="end">
                                <Button
                                  size="xs"
                                  variant="secondary"
                                  onClick={() => setEditingTaskId(null)}
                                >
                                  Cancel
                                </Button>
                                <Button
                                  size="xs"
                                  variant="primary"
                                  onClick={() => handleEditTask(task.id || '', editingTitle)}
                                >
                                  Save
                                </Button>
                              </Row>
                            )}

                            {/* Priority badge */}
                            {task.priority && (
                              <Badge variant={getPriorityVariant(task.priority)} size="sm" pill>
                                {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                              </Badge>
                            )}

                            {/* Assignee avatar */}
                            {task.assignee && (
                              <Row gap={8} align="center">
                                <Avatar name={task.assignee} size="sm" />
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{task.assignee}</Text>
                              </Row>
                            )}

                            {/* Due date */}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                📅 {task.dueDate}
                              </Text>
                            )}

                            {/* Move to column dropdown */}
                            {props.columns.length > 1 && (
                              <Dropdown
                                trigger={<Button size="xs" variant="outline">Move to...</Button>}
                                value={task.column || ''}
                                onChange={(newCol) => handleMoveTask(task.id || '', newCol)}
                                options={props.columns
                                  .filter((c) => c.id !== colId)
                                  .map((c) => ({
                                    value: c.id || '',
                                    label: c.name || 'Untitled',
                                  }))}
                              />
                            )}
                          </Stack>
                        </Card>
                      ))
                    ) : (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
                        No tasks
                      </Text>
                    )}
                  </Stack>

                  {/* Add Task form toggle */}
                  {!isAddingTask ? (
                    <Button
                      size="sm"
                      variant="secondary"
                      fullWidth
                      onClick={() => setShowAddForm((prev) => ({ ...prev, [colId]: true }))}
                    >
                      + Add Task
                    </Button>
                  ) : (
                    <Stack gap={12} style={{ padding: 'var(--ggui-spacing-3)', background: 'var(--ggui-color-surfaceVariant)', borderRadius: 'var(--ggui-shape-radius-md)' }}>
                      <Input
                        label="Task title"
                        placeholder="Enter task title..."
                        value={newTaskTitle[colId] || ''}
                        onChange={(val) => setNewTaskTitle((prev) => ({ ...prev, [colId]: val }))}
                        size="sm"
                      />
                      <Select
                        label="Priority"
                        value={newTaskPriority[colId] || 'low'}
                        onChange={(val) => setNewTaskPriority((prev) => ({ ...prev, [colId]: val as 'low' | 'medium' | 'high' }))}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                        size="sm"
                      />
                      <Row gap={8} justify="end">
                        <Button
                          size="xs"
                          variant="secondary"
                          onClick={() => setShowAddForm((prev) => ({ ...prev, [colId]: false }))}
                        >
                          Cancel
                        </Button>
                        <Button
                          size="xs"
                          variant="primary"
                          onClick={() => handleCreateTask(colId)}
                        >
                          Create
                        </Button>
                      </Row>
                    </Stack>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

