// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  // State for search and selected element
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [searchQuery, props.elements]);

  // Get unique categories and their colors
  const categoriesMap = useMemo(() => {
    const map: Record<string, string> = {};
    const categoryColors: Record<string, string> = {
      'alkali-metal': 'var(--ggui-color-warning-100, #fef3c7)',
      'alkaline-earth-metal': 'var(--ggui-color-info-100, #cffafe)',
      'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      'post-transition-metal': 'var(--ggui-color-primary-50, #f0f9ff)',
      'metalloid': 'var(--ggui-color-secondary-100, #e5e7eb)',
      'nonmetal': 'var(--ggui-color-success-100, #dcfce7)',
      'halogen': 'var(--ggui-color-error-100, #fee2e2)',
      'noble-gas': 'var(--ggui-color-neutral-100, #f3f4f6)',
      'lanthanide': 'var(--ggui-color-warning-50, #fffbeb)',
      'actinide': 'var(--ggui-color-error-50, #fef2f2)',
    };
    props.elements.forEach(el => {
      if (el.category && !map[el.category]) {
        map[el.category] = categoryColors[el.category] || 'var(--ggui-color-surface, #fafafa)';
      }
    });
    return map;
  }, [props.elements]);

  // Get sorted unique categories
  const categories = useMemo(() => {
    return Object.keys(categoriesMap).sort();
  }, [categoriesMap]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)" center={false}>
      <Stack gap={24} direction="vertical">
        {/* Header */}
        <Stack gap={8} direction="vertical">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Explore the periodic table. Click an element for more details.
          </Text>
        </Stack>

        {/* Search input */}
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          placeholder="Search by name or symbol..."
          size="md"
        />

        {/* Legend */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
          <Stack direction="vertical" gap={12}>
            <Text variant="label" weight="semibold">Legend</Text>
            <Stack direction="horizontal" gap={16} wrap={true} align="start">
              {categories.map(cat => (
                <Stack key={cat} direction="horizontal" gap={6} align="center">
                  <Box
                    padding="var(--ggui-spacing-2)"
                    background={categoriesMap[cat]}
                    borderRadius={4}
                    style={{ minWidth: '20px', minHeight: '20px' }}
                  />
                  <Text variant="bodySmall">{cat}</Text>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Box>

        {/* Periodic Table Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))',
          gap: '8px',
          padding: 'var(--ggui-spacing-4)',
          background: 'var(--ggui-color-surface, #fafafa)',
          borderRadius: '8px',
          border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        }}>
          {props.elements.map(el => {
            if (!el.symbol) return null;
            const isFiltered = !filteredElements.includes(el);
            const isSelected = selectedElement === el;
            const bgColor = categoriesMap[el.category || ''] || 'var(--ggui-color-surface, #fafafa)';

            return (
              <Card
                key={el.symbol}
                as={Clickable}
                onClick={() => setSelectedElement(el)}
                padding="var(--ggui-spacing-2)"
                shadow="sm"
                radius="md"
                style={{
                  gridRow: el.row || 1,
                  gridColumn: el.col || 1,
                  background: bgColor,
                  cursor: 'pointer',
                  transition: 'all 200ms ease-in-out',
                  opacity: isFiltered ? 0.3 : 1,
                  transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'var(--ggui-shape-shadow-sm)',
                  border: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                }}
                hoverStyle={{ transform: isFiltered ? 'scale(1)' : 'scale(1.02)', opacity: 1 }}
              >
                <Stack gap={4} direction="vertical" justify="center" align="center" style={{ height: '100%' }}>
                  {/* Atomic number (top-left) */}
                  {el.atomicNumber !== undefined && (
                    <Text
                      variant="caption"
                      size="xs"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      style={{ alignSelf: 'flex-start' }}
                    >
                      {el.atomicNumber}
                    </Text>
                  )}
                  {/* Symbol (large, centered) */}
                  <Text
                    variant="label"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                    align="center"
                  >
                    {el.symbol}
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </div>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
            <Stack gap={12} direction="vertical">
              <Stack gap={8} direction="vertical">
                <Heading level={2}>{selectedElement.name || 'Unknown'}</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Element Details
                </Text>
              </Stack>

              <Divider />

              <Stack gap={16} direction="vertical">
                {/* Symbol */}
                <Stack direction="horizontal" gap={16} align="start">
                  <Text variant="label" style={{ minWidth: '120px' }}>
                    Symbol:
                  </Text>
                  <Badge variant="primary" size="lg">
                    {selectedElement.symbol}
                  </Badge>
                </Stack>

                {/* Atomic Number */}
                {selectedElement.atomicNumber !== undefined && (
                  <Stack direction="horizontal" gap={16} align="center">
                    <Text variant="label" style={{ minWidth: '120px' }}>
                      Atomic Number:
                    </Text>
                    <Text variant="body">{selectedElement.atomicNumber}</Text>
                  </Stack>
                )}

                {/* Atomic Weight */}
                {selectedElement.atomicWeight !== undefined && (
                  <Stack direction="horizontal" gap={16} align="center">
                    <Text variant="label" style={{ minWidth: '120px' }}>
                      Atomic Weight:
                    </Text>
                    <Text variant="body">{selectedElement.atomicWeight.toFixed(2)}</Text>
                  </Stack>
                )}

                {/* Category */}
                {selectedElement.category && (
                  <Stack direction="horizontal" gap={16} align="center">
                    <Text variant="label" style={{ minWidth: '120px' }}>
                      Category:
                    </Text>
                    <Stack direction="horizontal" gap={4} align="center">
                      <Box
                        padding="var(--ggui-spacing-1)"
                        background={categoriesMap[selectedElement.category] || 'var(--ggui-color-surface)'}
                        borderRadius={4}
                        style={{ minWidth: '16px', minHeight: '16px' }}
                      />
                      <Text variant="body">{selectedElement.category}</Text>
                    </Stack>
                  </Stack>
                )}
              </Stack>

              <Divider />

              {/* Close button */}
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSelectedElement(null)}
              >
                Close Details
              </Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

