import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  const [activeTab, setActiveTab] = useState('description');
  const [quantity, setQuantity] = useState(1);

  const stock = props.product.stock ?? 0;
  const isOutOfStock = stock === 0;
  const maxQuantity = Math.max(1, stock);

  const formatPrice = (price: number, currency: string) => {
    const currencySymbols: Record<string, string> = {
      'USD': '$',
      'EUR': '€',
      'GBP': '£',
      'JPY': '¥',
      'CAD': '$',
      'AUD': '$',
    };
    const symbol = currencySymbols[currency] || currency;
    return `${symbol}${price.toFixed(2)}`;
  };

  const handleQuantityChange = (newQuantity: number) => {
    const clamped = Math.max(1, Math.min(newQuantity, maxQuantity));
    setQuantity(clamped);
  };

  const handleAddToCart = () => {
    if (props.product.id && !isOutOfStock) {
      addToCart({ productId: props.product.id, quantity });
    }
  };

  const renderStars = (rating: number) => {
    return (
      <Row gap="var(--ggui-spacing-1)" align="center">
        {[1, 2, 3, 4, 5].map((star) => (
          <Icon key={star} name={star <= rating ? 'star' : 'star'} size={16} color={star <= rating ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'} />
        ))}
      </Row>
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Image, Title, Price, Rating, Stock */}
         <Stack gap="var(--ggui-spacing-8)" style={{ display: 'flex', flexDirection: window.innerWidth < 768 ? 'column' : 'row', alignItems: 'flex-start' }}>
           {/* Product Image Placeholder */}
           <Box
             background="var(--ggui-color-primary-50, #f0f9ff)"
             borderRadius="var(--ggui-shape-radius-lg, 12px)"
             style={{ width: window.innerWidth < 768 ? '100%' : '300px', height: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}
           >
             <Stack align="center" gap="var(--ggui-spacing-2)">
               <Icon name="image" size={48} color="var(--ggui-color-primary-300, #7dd3fc)" />
               <Text variant="bodySmall" color="var(--ggui-color-primary-600, #0284c7)">
                 {props.product.name || 'Product Image'}
               </Text>
             </Stack>
           </Box>

           {/* Product Details */}
           <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, width: window.innerWidth < 768 ? '100%' : 'auto' }}>
             <Stack gap="var(--ggui-spacing-2)">
               <Heading level={1}>{props.product.name || 'Product Name'}</Heading>
               <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center" style={{ flexWrap: 'wrap' }}>
                 <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
                   {formatPrice(props.product.price ?? 0, props.product.currency ?? 'USD')}
                 </Text>
                 <Row gap="var(--ggui-spacing-2)" align="center">
                   {renderStars(props.product.rating ?? 0)}
                   <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                     ({props.product.reviewCount ?? 0})
                   </Text>
                 </Row>
               </Stack>
             </Stack>

             {/* Stock Badge */}
             <Badge variant={isOutOfStock ? 'error' : stock < 5 ? 'warning' : 'success'}>
               {isOutOfStock ? 'Out of Stock' : stock < 5 ? 'Low Stock' : 'In Stock'}
             </Badge>
           </Stack>
         </Stack>

        {/* Middle Section: Tabs */}
        <Card shadow="sm" padding="var(--ggui-spacing-4)">
          <Tabs
            items={[
              { key: 'description', label: 'Description', content: <Text>{props.product.description || 'No description available'}</Text> },
              { key: 'specifications', label: 'Specifications', content: renderSpecifications() },
              { key: 'reviews', label: 'Reviews', content: renderReviews() },
            ]}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
          />
        </Card>

        {/* Bottom Section: Quantity & Add to Cart */}
        <Card shadow="sm" padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center">
            <Stack gap="var(--ggui-spacing-2)" align="start">
              <Text variant="label">Quantity</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(quantity - 1)}
                  disabled={quantity <= 1 || isOutOfStock}
                >
                  −
                </Button>
                <Text style={{ minWidth: '40px', textAlign: 'center' }}>{quantity}</Text>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(quantity + 1)}
                  disabled={quantity >= maxQuantity || isOutOfStock}
                >
                  +
                </Button>
              </Row>
            </Stack>
            <Spacer size="flex" />
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={isOutOfStock}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );

  function renderSpecifications() {
    const specs = props.product.specifications || [];
    if (specs.length === 0) return <Text>No specifications available</Text>;
    return (
      <Table
        columns={[
          { key: 'key', header: 'Name' },
          { key: 'value', header: 'Value' },
        ]}
        data={specs as Array<{ key: string; value: string }>}
      />
    );
  }

  function renderReviews() {
    const reviews = props.product.reviews || [];
    if (reviews.length === 0) return <Text>No reviews available</Text>;
    return (
      <Stack gap="var(--ggui-spacing-4)">
        {reviews.map((review: any, idx: number) => (
          <Card key={idx} padding="var(--ggui-spacing-4)" shadow="none" border={true}>
            <Stack gap="var(--ggui-spacing-2)">
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Text weight="semibold">{review.author || 'Anonymous'}</Text>
                {renderStars(review.rating || 0)}
              </Row>
              <Text>{review.text || review.content || ''}</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {review.date ? new Date(review.date).toLocaleDateString() : 'No date'}
              </Text>
            </Stack>
          </Card>
        ))}
      </Stack>
    );
  }

