  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messageText, setMessageText] = useState<string>('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [typingIndicator, setTypingIndicator] = useState<{ sender?: string; active?: boolean } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  // Handle typing indicator
  // Handle typing indicator
  useEffect(() => {
    if (typing.latest?.active && typing.latest?.sender !== props.currentUser) {
      setTypingIndicator(typing.latest);
    } else if (!typing.latest?.active) {
      setTypingIndicator(null);
    }
  }, [typing.latest, props.currentUser]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: messageText, timestamp });
