}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Wire hooks — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  // State: manage stock data with price updates merged in
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const highlightedSymbols = useRef<Set<string>>(new Set());
  const [highlightedSet, setHighlightedSet] = useState<Set<string>>(new Set());

  // Merge incoming price updates into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) => {
        const updated = prevStocks.map((stock) => {
          if (stock.symbol === update.symbol) {
            // Mark for highlight animation
            highlightedSymbols.current.add(update.symbol || '');
            setHighlightedSet(new Set(highlightedSymbols.current));
            // Clear highlight after 600ms
            setTimeout(() => {
              highlightedSymbols.current.delete(update.symbol || '');
              setHighlightedSet(new Set(highlightedSymbols.current));
            }, 600);
            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  // Update props when initial stocks prop changes
  useEffect(() => {
    if (props.stocks && props.stocks.length > 0) {
      setStocks(props.stocks);
    }
  }, [props.stocks]);

  // Format price to 2 decimals
  const formatPrice = (price?: number): string => {
    if (price === undefined) return 'N/A';
    return `$${price.toFixed(2)}`;
  };

  // Determine color based on change
  const getChangeColor = (change?: number): string => {
    if (change === undefined) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
    if (change > 0) return 'var(--ggui-color-success-500, #22c55e)';
    if (change < 0) return 'var(--ggui-color-error-500, #ef4444)';
    return 'var(--ggui-color-onSurfaceVariant, #52525b)';
  };

  // Get change arrow
  const getChangeArrow = (change?: number): string => {
    if (change === undefined) return '';
    return change > 0 ? '▲' : change < 0 ? '▼' : '';
  };

  // Format change to 2 decimals with sign
  const formatChange = (change?: number): string => {
    if (change === undefined) return 'N/A';
    const sign = change > 0 ? '+' : '';
    return `${sign}${change.toFixed(2)}`;
  };

  // Format change percent to 2 decimals with sign
  const formatChangePercent = (changePercent?: number): string => {
    if (changePercent === undefined) return 'N/A';
    const sign = changePercent > 0 ? '+' : '';
    return `${sign}${changePercent.toFixed(2)}%`;
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={8} align="center" direction="horizontal" justify="between">
          <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Heading>
          <Stack direction="horizontal" gap={8} align="center">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated:
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" weight="medium">
              {lastUpdated.toLocaleTimeString()}
            </Text>
          </Stack>
        </Stack>

        {/* Stock Cards Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-6, 24px)',
            '@media (max-width: 640px)': {
              gridTemplateColumns: '1fr',
            },
          }}
        >
          {stocks.map((stock) => {
            const changeColor = getChangeColor(stock.change);
            const isHighlighted = highlightedSet.has(stock.symbol || '');

            return (
              <Card
                key={stock.symbol}
                padding={20}
                shadow="md"
                radius="lg"
                style={{
                  borderLeft: `4px solid ${changeColor}`,
                  backgroundColor: isHighlighted
                    ? 'var(--ggui-color-primary-50, #f0f9ff)'
                    : 'var(--ggui-color-surface, #ffffff)',
                  transition: 'background-color 0.3s ease',
                }}
              >
                <Stack gap={12}>
                  {/* Ticker Symbol (large, bold) */}
                  <Text
                    variant="label"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {stock.symbol || 'N/A'}
                  </Text>

                  {/* Company Name */}
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {stock.name || 'Unknown Company'}
                  </Text>

                  {/* Current Price */}
                  <Text
                    size="xl"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {formatPrice(stock.price)}
                  </Text>

                  {/* Change Amount & Percentage (with arrow) */}
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text
                      variant="body"
                      weight="medium"
                      color={changeColor}
                    >
                      {formatChange(stock.change)}
                    </Text>
                    <Text
                      variant="body"
                      weight="medium"
                      color={changeColor}
                    >
                      {getChangeArrow(stock.change)} {formatChangePercent(stock.changePercent)}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </Box>

        {/* Empty state */}
        {stocks.length === 0 && (
          <Box padding={40} style={{ textAlign: 'center' }}>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No stocks to display
            </Text>
