                        cursor: 'pointer',
                        padding: 'var(--ggui-spacing-2)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        border: avatar === opt ? '3px solid var(--ggui-color-primary-600, #0284c7)' : '3px solid var(--ggui-color-outline, #d4d4d8)',
                        transition: 'all 200ms ease',
                      }}
                      hoverStyle={{ opacity: 0.8 }}
                    >
                      {opt}
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3} align="center">
                Preferences
              </Heading>

              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={roleSelectOptions}
                placeholder="Select your role"
              />

              <Toggle
                label="Email Notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
              />

              <Stack gap="var(--ggui-spacing-2)" align="start">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Theme
                </Text>
                <RadioGroup
                  value={theme}
                  onChange={setTheme}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                  direction="horizontal"
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3} align="center">
                Review & Confirm
              </Heading>

              <Stack gap="var(--ggui-spacing-4)" align="start" style={{ width: '100%' }}>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)" style={{ width: '100%' }}>
                  <Stack gap="var(--ggui-spacing-3)" align="start">
                    <Stack gap="var(--ggui-spacing-1)" align="start" style={{ width: '100%' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Name
                      </Text>
                      <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                        {name}
                      </Text>
                    </Stack>

                    <Stack gap="var(--ggui-spacing-1)" align="start" style={{ width: '100%' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Email
                      </Text>
                      <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                        {email}
                      </Text>
                    </Stack>

                    <Stack gap="var(--ggui-spacing-1)" align="start" style={{ width: '100%' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Avatar
                      </Text>
                      <Text variant="body" style={{ fontSize: '32px' }}>
                        {avatar}
                      </Text>
                    </Stack>

                    <Stack gap="var(--ggui-spacing-1)" align="start" style={{ width: '100%' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Role
                      </Text>
                      <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                        {role || 'Not selected'}
                      </Text>
                    </Stack>

                    <Stack gap="var(--ggui-spacing-1)" align="start" style={{ width: '100%' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Email Notifications
                      </Text>
                      <Badge variant={emailNotifications ? 'success' : 'default'}>
                        {emailNotifications ? 'Enabled' : 'Disabled'}
                      </Badge>
                    </Stack>

                    <Stack gap="var(--ggui-spacing-1)" align="start" style={{ width: '100%' }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Theme
                      </Text>
                      <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" style={{ textTransform: 'capitalize' }}>
                        {theme}
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="center" align="center" style={{ width: '100%', maxWidth: '500px' }}>
          {currentStep > 1 && (
            <Button variant="ghost" onClick={handleBack} size="md">
              Back
            </Button>
          )}
          {currentStep < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={currentStep === 1 && (Object.keys(step1ValidationState).length > 0 || !name.trim() || !email.trim())}
              size="md"
            >
              Next
            </Button>
          )}
          {currentStep === 3 && (
            <Button variant="primary" onClick={handleComplete} size="md">
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
